            pending: { color: 'orange', text: 'Pending' },
            resolved: { color: 'green', text: 'Resolved' },
            approved: { color: 'blue', text: 'Approved' },
            ignored: { color: 'red', text: 'Ignored' }
          };
          const config = statusConfig[status] || { color: 'default', text: status || 'Unknown' };
          return <Tag color={config.color}>{config.text}</Tag>;
        }
      },
      {
        title: 'Received',
        dataIndex: 'createdAt',
        key: 'createdAt',
        render: (date) => moment(date).format('MMM DD, YYYY')
      },
      {
        title: 'Actions',
        key: 'actions',
        render: (_, record) => (
          <Space>
            <Button
              icon={<EyeOutlined />}
              size="small"
              onClick={() => {
                setSelectedMessage(record);
                setMessageModalVisible(true);
                if (record.status === 'pending') {
                  updateContactStatus(record._id, 'resolved');
                }
              }}
            >
              View
            </Button>
            {record.status === 'pending' && (
              <Button
                icon={<CheckOutlined />}
                size="small"
                type="primary"
                onClick={() => updateContactStatus(record._id, 'resolved')}
              >
                Mark Resolved
              </Button>
            )}
          </Space>
        )
      }
    ];

    const userColumns = [
      {
        title: 'User Info',
        key: 'userInfo',
        render: (_, record) => (
          <div>
            <Text strong>{record.firstName} {record.lastName}</Text>
            <br />
            <Text type="secondary" style={{ fontSize: '12px' }}>
              {record.email}
            </Text>
          </div>
        )
      },
      {
        title: 'Role',
        dataIndex: 'role',
        key: 'role',
        render: (role) => (
          <Tag color={role === 'teacher' ? 'blue' : role === 'student' ? 'green' : 'default'}>
            {role?.toUpperCase()}
          </Tag>
        )
      },
      {
        title: 'Status',
        dataIndex: 'isApproved',
        key: 'isApproved',
        render: (isApproved) => {
          if (isApproved === true) {
            return <Tag color="green" icon={<CheckCircleOutlined />}>Approved</Tag>;
          } else if (isApproved === false) {
            return <Tag color="red" icon={<CloseCircleOutlined />}>Rejected</Tag>;
          } else {
            return <Tag color="orange">Pending</Tag>;
          }
        }
      },
      {
        title: 'Registration Date',
        dataIndex: 'createdAt',
        key: 'createdAt',
        render: (date) => moment(date).format('MMM DD, YYYY')
      },
      {
        title: 'Actions',
        key: 'actions',
        render: (_, record) => (
          <Space>
            <Button
              icon={<EyeOutlined />}
              size="small"
              onClick={() => {
                setSelectedUser(record);
                setUserModalVisible(true);
              }}
            >
              View
            </Button>
            {record.isApproved !== true && (
              <Button
                icon={<CheckOutlined />}
                size="small"
                type="primary"
                style={{ backgroundColor: '#52c41a', borderColor: '#52c41a' }}
                onClick={() => updateUserStatus(record._id, true)}
              >
                Approve
              </Button>
            )}
            {record.isApproved !== false && (
              <Button
                icon={<CloseOutlined />}
                size="small"
                danger
                onClick={() => updateUserStatus(record._id, false)}
              >
                Reject
              </Button>
            )}
          </Space>
        )
      }
    ];

    const filteredApplications = applications.filter(app => {
      const matchesStatus = !filterStatus || app.status === filterStatus;
      const matchesSearch = !searchTerm || 
        app.fullName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        app.email?.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesStatus && matchesSearch;
    });

    const filteredMessages = contactMessages.filter(msg => {
      const matchesSearch = !searchTerm || 
        msg.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        msg.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        msg.subject?.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesSearch;
    });

    const filteredUsers = users.filter(user => {
      const matchesSearch = !searchTerm || 
        user.firstName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.lastName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.email?.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesRole = !roleFilter || user.role === roleFilter;
      return matchesSearch && matchesRole;
    });

    return (
      <div>
        <Title level={2}>📋 Application Management</Title>
        <Text type="secondary">Manage student applications, contact messages, and user registrations</Text>

        {/* Statistics Cards */}
        <Row gutter={[16, 16]} style={{ marginTop: '24px', marginBottom: '24px' }}>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Applications"
                value={dashboardStats.totalApplications}
                prefix={<UserOutlined />}
                valueStyle={{ color: '#1890ff' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Pending Review"
                value={dashboardStats.pendingApplications}
                prefix={<CalendarOutlined />}
                valueStyle={{ color: '#faad14' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Contact Messages"
                value={dashboardStats.totalMessages}
                prefix={<MessageOutlined />}
                valueStyle={{ color: '#52c41a' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Pending Users"
                value={users.filter(user => user.isApproved !== true && user.isApproved !== false).length}
                prefix={<UserOutlined />}
                valueStyle={{ color: '#f5222d' }}
              />
            </Card>
          </Col>
        </Row>

        {/* Tabs for different management sections */}
        <Tabs
          defaultActiveKey="applications"
          items={[
            {
              key: 'applications',
              label: '📝 Applications',
              children: (
                <Card 
                  title="Student Applications" 
                  extra={
                    <Space>
                      <Input
                        placeholder="Search applications..."
                        prefix={<SearchOutlined />}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ width: 200 }}
                      />
                      <Select
                        placeholder="Filter by status"
                        value={filterStatus}
                        onChange={setFilterStatus}
                        style={{ width: 150 }}
                        allowClear
                      >
                        <Select.Option value="pending">Pending</Select.Option>
                        <Select.Option value="approved">Approved</Select.Option>
                        <Select.Option value="rejected">Rejected</Select.Option>
                      </Select>
                    </Space>
                  }
                >
                  <Table
                    columns={applicationColumns}
                    dataSource={filteredApplications}
                    rowKey="_id"
                    pagination={{
                      pageSize: 10,
                      showSizeChanger: true,
                      showQuickJumper: true,
                    }}
                  />
                </Card>
              )
            },
            {
              key: 'contacts',
              label: '💬 Messages',
              children: (
                <Card 
                  title="Contact Messages"
                  extra={
                    <Space>
                      <Input
                        placeholder="Search messages..."
                        prefix={<SearchOutlined />}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ width: 200 }}
                      />
                      <Button icon={<DownloadOutlined />} type="primary">
                        Export Messages
                      </Button>
                    </Space>
                  }
                >
                  <Table
                    columns={messageColumns}
                    dataSource={filteredMessages}
                    rowKey="_id"
                    pagination={{
                      pageSize: 10,
                      showSizeChanger: true,
                      showQuickJumper: true,
                    }}
                  />
                </Card>
              )
            },
            {
              key: 'users',
              label: '👥 Users',
              children: (
                <Card 
                  title="User Registrations"
                  extra={
                    <Space>
                      <Input
                        placeholder="Search users..."
                        prefix={<SearchOutlined />}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ width: 200 }}
                      />
                      <Select
                        placeholder="Filter by role"
                        value={roleFilter}
                        onChange={(value) => setRoleFilter(value)}
                        style={{ width: 150 }}
                        allowClear
                      >
                        <Select.Option value="teacher">Teacher</Select.Option>
                        <Select.Option value="student">Student</Select.Option>
                        <Select.Option value="admin">Admin</Select.Option>
                      </Select>
                      <Button 
                        type="primary" 
                        icon={<UserOutlined />}
                        onClick={() => setCreateUserModalVisible(true)}
                      >
                        Create User
                      </Button>
                    </Space>
                  }
                >
                  <Table
                    columns={userColumns}
                    dataSource={filteredUsers}
                    rowKey="_id"
                    pagination={{
                      pageSize: 10,
                      showSizeChanger: true,
                      showQuickJumper: true,
                    }}
                  />
                </Card>
              )
            }
          ]}
        />
      </div>
    );
  };

  // Render Course Management
  const renderCourseManagement = () => {
    const courseColumns = [
      {
        title: 'Course Title',
        dataIndex: 'title',
        key: 'title',
        render: (title, record) => (
          <div>
            <Text strong>{title}</Text>
            <br />
            <Text type="secondary" style={{ fontSize: '12px' }}>
              Code: {record.code}
            </Text>
          </div>
        )
      },
      {
        title: 'Category',
        dataIndex: 'category',
        key: 'category',
        render: (category) => <Tag color="blue">{category}</Tag>
      },
      {
        title: 'Level',
        dataIndex: 'level',
        key: 'level',
        render: (level) => {
          const colors = {
            beginner: 'green',
            intermediate: 'orange',
            advanced: 'red'
          };
          return <Tag color={colors[level]}>{level?.toUpperCase()}</Tag>;
        }
      },
      {
        title: 'Students',
        dataIndex: 'students',
        key: 'students',
        render: (students) => (
          <Badge count={students?.length || 0} showZero>
            <TeamOutlined style={{ fontSize: 20 }} />
          </Badge>
        )
      },
      {
        title: 'Status',
        dataIndex: 'isActive',
        key: 'isActive',
        render: (isActive) => {
          return (
            <Tag color={isActive ? 'green' : 'default'}>
              {isActive ? 'Active' : 'Inactive'}
            </Tag>
          );
        }
      },
      {
        title: 'Actions',
        key: 'actions',
        render: (_, record) => (
          <Space>
            <Tooltip title="Edit">
              <Button
                icon={<EditOutlined />}
                size="small"
                onClick={() => {
                  setEditingCourse(record);
                  const formValues = {
                    ...record,
                    capacity: record.maxStudents || record.capacity || 30,
                    status: record.isActive ? 'active' : 'inactive'
                  };
                  
                  // Handle dates safely
                  if (record.startDate) {
                    const startDate = moment(record.startDate);
                    if (startDate.isValid()) {
                      formValues.startDate = startDate;
                    }
                  }
                  
                  if (record.endDate) {
                    const endDate = moment(record.endDate);
                    if (endDate.isValid()) {
                      formValues.endDate = endDate;
                    }
                  }
                  
                  courseForm.setFieldsValue(formValues);
                  setCourseModalVisible(true);
                }}
              />
            </Tooltip>
            <Tooltip title="View Details">
              <Button
                icon={<EyeOutlined />}
                size="small"
                onClick={() => {
                  setSelectedCourse(record);
                  setCourseViewModalVisible(true);
                }}
              />
            </Tooltip>
            <Popconfirm
              title="Are you sure you want to delete this course?"
              onConfirm={async () => {
                try {
                  await courseAPI.delete(record._id);
                  message.success('Course deleted successfully');
                  fetchCourses();
                } catch (error) {
                  message.error('Failed to delete course');
                }
              }}
            >
              <Tooltip title="Delete">
                <Button icon={<DeleteOutlined />} size="small" danger />
              </Tooltip>
            </Popconfirm>
          </Space>
        )
      }
    ];

    return (
      <div>
        <Title level={2}>📚 Course Management</Title>
        <Text type="secondary">Create and manage courses, curriculum, and enrollments</Text>

        <Row gutter={[16, 16]} style={{ marginTop: 24, marginBottom: 24 }}>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Courses"
                value={courses.length}
                prefix={<BookOutlined />}
                valueStyle={{ color: '#1890ff' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Active Courses"
                value={courses.filter(c => c.isActive !== false).length}
                prefix={<CheckCircleOutlined />}
                valueStyle={{ color: '#52c41a' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Enrolled"
                value={courses.reduce((sum, c) => sum + (c.students?.length || 0), 0)}
                prefix={<TeamOutlined />}
                valueStyle={{ color: '#faad14' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Avg. Completion"
                value={75}
                suffix="%"
                prefix={<TrophyOutlined />}
                valueStyle={{ color: '#722ed1' }}
              />
            </Card>
          </Col>
        </Row>

        <Card
          title="All Courses"
          extra={
            <Space>
              <Input
                placeholder="Search courses..."
                prefix={<SearchOutlined />}
                onChange={(e) => setSearchTerm(e.target.value)}
                style={{ width: 200 }}
              />
              <Select
                placeholder="Filter by category"
                style={{ width: 150 }}
                onChange={setSelectedCategory}
                allowClear
              >
                <Option value="language">Language</Option>
                <Option value="business">Business</Option>
                <Option value="technology">Technology</Option>
                <Option value="arts">Arts</Option>
                <Option value="science">Science</Option>
                <Option value="other">Other</Option>
              </Select>
              <Button
                type="primary"
                icon={<PlusOutlined />}
                onClick={() => {
                  setEditingCourse(null);
                  courseForm.resetFields();
                  setCourseModalVisible(true);
                }}
              >
                Create Course
              </Button>
            </Space>
          }
        >
          <Table
            columns={courseColumns}
            dataSource={courses.filter(course => {
              const matchesSearch = !searchTerm || 
                course.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                course.code?.toLowerCase().includes(searchTerm.toLowerCase());
              const matchesCategory = !selectedCategory || course.category === selectedCategory;
              return matchesSearch && matchesCategory;
            })}
            rowKey="_id"
            pagination={{
              pageSize: 10,
              showSizeChanger: true,
              showQuickJumper: true
            }}
          />
        </Card>
      </div>
    );
  };

  // Render Material Management
  const renderMaterialManagement = () => {
    const materialColumns = [
      {
        title: 'Material',
        key: 'material',
        render: (_, record) => (
          <Space>
            {record.fileType === 'video' ? <VideoCameraOutlined /> : 
             record.fileType === 'pdf' ? <FileTextOutlined /> : 
             <FileOutlined />}
            <div>
              <Text strong>{record.title}</Text>
              <br />
              <Text type="secondary" style={{ fontSize: '12px' }}>
                {record.description}
              </Text>
            </div>
          </Space>
        )
      },
      {
        title: 'Course',
        dataIndex: 'course',
        key: 'course',
        render: (course) => {
          const courseData = courses.find(c => c._id === course);
          return <Tag color="blue">{courseData?.title || 'Unknown'}</Tag>;
        }
      },
      {
        title: 'Category',
        dataIndex: 'category',
        key: 'category',
        render: (category) => <Tag>{category}</Tag>
      },
      {
        title: 'Size',
        dataIndex: 'fileSize',
        key: 'fileSize',
        render: (size) => {
          const sizeInMB = (size / (1024 * 1024)).toFixed(2);
          return `${sizeInMB} MB`;
        }
      },
      {
        title: 'Uploaded',
        dataIndex: 'createdAt',
        key: 'createdAt',
        render: (date) => moment(date).format('MMM DD, YYYY')
      },
      {
        title: 'Actions',
        key: 'actions',
        render: (_, record) => (
          <Space>
            <Tooltip title="Download">
              <Button
                icon={<DownloadOutlined />}
                size="small"
                onClick={() => {
                  // Remove duplicate '/uploads/' prefix if filePath already contains it
                  const filePath = record.filePath.startsWith('uploads/') ?
                    record.filePath : `uploads/${record.filePath}`;
                  window.open(`${API_BASE_URL}/${filePath}`, '_blank');
                }}
              />
            </Tooltip>
            <Tooltip title="Preview">
              <Button
                icon={<EyeOutlined />}
                size="small"
                onClick={() => {
                  setSelectedMaterial(record);
                  setPreviewModalVisible(true);
                }}
              />
            </Tooltip>
            <Popconfirm
              title="Are you sure you want to delete this material?"
              onConfirm={async () => {
                try {
                  await materialAPI.delete(record._id);
                  message.success('Material deleted successfully');
                  fetchMaterials();
                } catch (error) {
                  message.error('Failed to delete material');
                }
              }}
            >
              <Tooltip title="Delete">
                <Button icon={<DeleteOutlined />} size="small" danger />
              </Tooltip>
            </Popconfirm>
          </Space>
        )
      }
    ];

    return (
      <div>
        <Title level={2}>📁 Course Materials</Title>
        <Text type="secondary">Upload and manage course materials, documents, and resources</Text>

        <Row gutter={[16, 16]} style={{ marginTop: 24, marginBottom: 24 }}>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Materials"
                value={materials.length}
                prefix={<FolderOutlined />}
                valueStyle={{ color: '#1890ff' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Videos"
                value={materials.filter(m => m.category === 'video').length}
                prefix={<VideoCameraOutlined />}
                valueStyle={{ color: '#52c41a' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Documents"
                value={materials.filter(m => m.category === 'document').length}
                prefix={<FileTextOutlined />}
                valueStyle={{ color: '#faad14' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Size"
                value={(materials.reduce((sum, m) => sum + (m.fileSize || 0), 0) / (1024 * 1024)).toFixed(1)}
                suffix="MB"
                prefix={<CloudOutlined />}
                valueStyle={{ color: '#722ed1' }}
              />
            </Card>
          </Col>
        </Row>

        <Card
          title="Course Materials"
          extra={
            <Space>
              <Input
                placeholder="Search materials..."
                prefix={<SearchOutlined />}
                onChange={(e) => setSearchTerm(e.target.value)}
                style={{ width: 200 }}
              />
              <Select
                placeholder="Filter by type"
                style={{ width: 150 }}
                onChange={setSelectedFileType}
                allowClear
              >
                <Option value="video">Videos</Option>
                <Option value="document">Documents</Option>
                <Option value="resource">Resources</Option>
              </Select>
              <Button
                type="primary"
                icon={<UploadOutlined />}
                onClick={() => {
                  materialForm.resetFields();
                  setFileList([]);
                  setMaterialModalVisible(true);
                }}
              >
                Upload Material
              </Button>
            </Space>
          }
        >
          <Table
            columns={materialColumns}
            dataSource={materials.filter(material => {
              const matchesSearch = !searchTerm || 
                material.title?.toLowerCase().includes(searchTerm.toLowerCase());
              const matchesType = !selectedFileType || material.category === selectedFileType;
              return matchesSearch && matchesType;
            })}
            rowKey="_id"
            pagination={{
              pageSize: 10,
              showSizeChanger: true,
              showQuickJumper: true
            }}
          />
        </Card>
      </div>
    );
  };

  // Render Quiz Management
  const renderQuizManagement = () => {
    const quizColumns = [
      {
        title: 'Quiz Title',
        dataIndex: 'title',
        key: 'title',
        render: (title, record) => (
          <div>
            <Text strong>{title}</Text>
            <br />
            <Text type="secondary" style={{ fontSize: '12px' }}>
              {record.questions?.length || 0} questions
            </Text>
          </div>
        )
      },
      {
        title: 'Course',
        dataIndex: 'course',
        key: 'course',
        render: (course) => {
          const courseData = courses.find(c => c._id === course);
          return <Tag color="blue">{courseData?.title || 'Unknown'}</Tag>;
        }
      },
      {
        title: 'Duration',
        dataIndex: 'duration',
        key: 'duration',
        render: (duration) => `${duration} mins`
      },
      {
        title: 'Passing Score',
        dataIndex: 'passingScore',
        key: 'passingScore',
        render: (score) => (
          <Progress
            percent={score}
            size="small"
            strokeColor={score >= 70 ? '#52c41a' : '#faad14'}
          />
        )
      },
      {
        title: 'Submissions',
        key: 'submissions',
        render: (_, record) => (
          <Badge count={record.submissions?.length || 0} showZero>
            <Button
              size="small"
              onClick={() => {
                setSelectedQuiz(record);
                fetchQuizSubmissions(record._id);
                setSubmissionsModalVisible(true);
              }}
            >
              View
            </Button>
          </Badge>
        )
      },
      {
        title: 'Status',
        key: 'status',
        render: (_, record) => {
          const now = moment();
          const availableFrom = record.availableFrom ? moment(record.availableFrom) : null;
          const availableTo = record.availableTo ? moment(record.availableTo) : null;
          
          let status = 'draft';
          let color = 'default';
          
          if (availableFrom && availableTo) {
            if (now.isBefore(availableFrom)) {
              status = 'scheduled';
              color = 'orange';
            } else if (now.isAfter(availableTo)) {
              status = 'expired';
              color = 'red';
            } else {
              status = 'active';
              color = 'green';
            }
          }
          
          return <Tag color={color}>{status.toUpperCase()}</Tag>;
        }
      },
      {
        title: 'Actions',
        key: 'actions',
        render: (_, record) => (
          <Space>
            <Tooltip title="Edit">
              <Button
                icon={<EditOutlined />}
                size="small"
                onClick={() => {
                  setEditingQuiz(record);
                  setQuestions(record.questions || []);
                  quizForm.setFieldsValue({
                    ...record,
                    availableFrom: record.availableFrom ? moment(record.availableFrom) : null,
                    availableTo: record.availableTo ? moment(record.availableTo) : null
                  });
                  setQuizModalVisible(true);
                }}
              />
            </Tooltip>
            <Tooltip title="Preview">
              <Button
                icon={<EyeOutlined />}
                size="small"
                onClick={() => {
                  setSelectedQuiz(record);
                  setPreviewModalVisible(true);
                }}
              />
            </Tooltip>
            <Tooltip title="Results">
              <Button
                icon={<BarChartOutlined />}
                size="small"
                onClick={() => {
                  setSelectedQuiz(record);
                  setResultsModalVisible(true);
                }}
              />
            </Tooltip>
            <Popconfirm
              title="Are you sure you want to delete this quiz?"
              onConfirm={async () => {
                try {
                  await quizAPI.delete(record._id);
                  message.success('Quiz deleted successfully');
                  fetchQuizzes();
                } catch (error) {
                  message.error('Failed to delete quiz');
                }
              }}
            >
              <Tooltip title="Delete">
                <Button icon={<DeleteOutlined />} size="small" danger />
              </Tooltip>
            </Popconfirm>
          </Space>
        )
      }
    ];

    return (
      <div>
        <Title level={2}>📝 Quiz Management</Title>
        <Text type="secondary">Create and manage quizzes, assessments, and evaluations</Text>

        <Row gutter={[16, 16]} style={{ marginTop: 24, marginBottom: 24 }}>
          <Col xs={24} sm={12} md={6}>
