                onClick={() => {
                  if (playingExerciseId === record._id && isPlaying) {
                    setIsPlaying(false);
                    setPlayingExerciseId(null);
                  } else {
                    setIsPlaying(true);
                    setPlayingExerciseId(record._id);
                  }
                }}
