              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Beginner Level"
                value={listeningExercises.filter(e => e.level === 'beginner').length}
                prefix={<StarOutlined />}
                valueStyle={{ color: '#52c41a' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Questions"
                value={listeningExercises.reduce((sum, e) => sum + (e.questions?.length || 0), 0)}
                prefix={<QuestionCircleOutlined />}
                valueStyle={{ color: '#faad14' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Avg. Duration"
                value={Math.round(listeningExercises.reduce((sum, e) => sum + (e.duration || 0), 0) / listeningExercises.length || 0)}
                suffix="sec"
                prefix={<ClockCircleOutlined />}
                valueStyle={{ color: '#722ed1' }}
              />
            </Card>
          </Col>
        </Row>

        <Card
          title="Listening Exercises"
          extra={
            <Space>
              <Input
                placeholder="Search exercises..."
                prefix={<SearchOutlined />}
                onChange={(e) => setSearchTerm(e.target.value)}
                style={{ width: 200 }}
              />
              <Button
                type="primary"
                icon={<PlusOutlined />}
                onClick={() => {
                  setEditingExercise(null);
                  setQuestions([]);
                  setAudioFile(null);
                  exerciseForm.resetFields();
                  setExerciseModalVisible(true);
                }}
              >
                Create Exercise
              </Button>
            </Space>
          }
        >
          <Table
            columns={exerciseColumns}
            dataSource={listeningExercises.filter(exercise => {
              const matchesSearch = !searchTerm || 
                exercise.title?.toLowerCase().includes(searchTerm.toLowerCase());
              return matchesSearch;
            })}
            rowKey="_id"
            pagination={{
              pageSize: 10,
              showSizeChanger: true,
              showQuickJumper: true
            }}
          />
        </Card>
      </div>
    );
